import{_ as r,o as a,c as e,ag as o,ah as d}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"深度搜索","description":"","frontmatter":{},"headers":[],"relativePath":"features/deep-search.md","filePath":"features/deep-search.md"}'),s={name:"features/deep-search.md"};function n(h,t,l,i,c,g){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="深度搜索" tabindex="-1">深度搜索 <a class="header-anchor" href="#深度搜索" aria-label="Permalink to &quot;深度搜索&quot;">​</a></h1><p>深度搜索（v0.9.8 起）在侧栏「按标题筛选任务」的基础上更进一步：<strong>跨全部工作区检索任务标题与会话内容</strong>，命中结果以高亮片段列出，点击即可进入对应任务并<strong>滚动定位到那条消息</strong>。想找「上次让 AI 改过某个函数的那次对话」，再也不用逐个任务翻历史。</p><blockquote><p>相关基础：<a href="/docs/features/tasks-and-workspaces.html#搜索任务">任务与工作区</a></p></blockquote><p><img src="'+d+'" alt="截图：深度搜索弹窗打开，输入关键词后结果按任务分组，组头显示任务标题与 CLI 徽标，组内为带高亮的消息片段"></p><hr><h2 id="打开深度搜索" tabindex="-1">打开深度搜索 <a class="header-anchor" href="#打开深度搜索" aria-label="Permalink to &quot;打开深度搜索&quot;">​</a></h2><p>两种方式：</p><ul><li>点击侧栏搜索框右侧的<strong>深度搜索</strong>按钮（放大镜加文本行的图标，悬浮提示「深度搜索（标题与会话内容）」）。若搜索框里已输入了关键词，会自动带入弹窗作为初始查询。</li><li>任意界面按 <strong>Ctrl+Shift+F</strong>（macOS 为 <strong>Cmd+Shift+F</strong>）。</li></ul><p>弹窗顶部是搜索输入框（自动聚焦）与<strong>包含归档</strong>勾选项，下方为结果列表。按 <code>Esc</code> 或点击弹窗外部即可关闭。</p><hr><h2 id="检索范围与匹配规则" tabindex="-1">检索范围与匹配规则 <a class="header-anchor" href="#检索范围与匹配规则" aria-label="Permalink to &quot;检索范围与匹配规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>规则</th></tr></thead><tbody><tr><td><strong>任务标题</strong></td><td>全部任务（不分 CLI）都参与标题匹配</td></tr><tr><td><strong>会话内容</strong></td><td>检索<strong>用户消息、AI 回复与思考过程</strong>的文本；Claude 与 Codex 任务支持内容检索，<strong>OpenCode 任务目前仅参与标题匹配</strong></td></tr><tr><td><strong>不检索</strong></td><td>工具调用的输入 / 输出、子智能体内部对话</td></tr><tr><td><strong>多个关键词</strong></td><td>用空格分隔，视为「同时包含」——所有词都出现在<strong>同一条消息</strong>（或同一个标题）里才算命中</td></tr><tr><td><strong>大小写</strong></td><td>不敏感</td></tr><tr><td><strong>归档任务</strong></td><td>默认不搜；勾选<strong>包含归档</strong>后参与，命中的归档任务带「已归档」徽标</td></tr></tbody></table><hr><h2 id="结果的读法" tabindex="-1">结果的读法 <a class="header-anchor" href="#结果的读法" aria-label="Permalink to &quot;结果的读法&quot;">​</a></h2><p>结果<strong>按任务分组</strong>（类似 VS Code 的全局搜索）：</p><ul><li><strong>组头</strong>：任务标题（命中部分高亮）+ CLI 徽标 + 「已归档」徽标（仅归档任务）+ 最近活动的相对时间。点击组头 = 仅打开该任务。</li><li><strong>片段行</strong>：角色小图标（用户 / 助手 / 思考）+ 命中消息的上下文片段，关键词高亮。每个任务最多列出 5 条片段。</li></ul><p>结果过多时列表底部会提示「结果已截断，请细化关键词」——加个更具体的词再搜即可。</p><h3 id="键盘操作" tabindex="-1">键盘操作 <a class="header-anchor" href="#键盘操作" aria-label="Permalink to &quot;键盘操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按键</th><th>功能</th></tr></thead><tbody><tr><td><code>↑</code> / <code>↓</code></td><td>在组头与片段之间上下移动高亮</td></tr><tr><td><code>Enter</code></td><td>打开当前高亮项</td></tr><tr><td><code>Esc</code></td><td>关闭弹窗</td></tr></tbody></table><hr><h2 id="跳转定位" tabindex="-1">跳转定位 <a class="header-anchor" href="#跳转定位" aria-label="Permalink to &quot;跳转定位&quot;">​</a></h2><p>点击某条<strong>片段</strong>后，弹窗关闭，LoongCode 会在当前分栏打开该任务，自动滚动到命中的那条消息并<strong>闪烁两下</strong>提示位置；侧栏也会同步展开并定位到该任务所在分组。</p><div class="tip custom-block"><p class="custom-block-title">定位偶尔会「退化」为只进任务</p><p>搜索结果基于磁盘上的会话快照。如果点击时该会话恰好被<a href="/docs/features/conversation.html#编辑历史消息重跑">编辑重跑</a>、回滚或分叉过，原来的消息位置可能已不存在——此时会安全地退化为只打开任务、不做定位，不会闪烁到错误的消息上。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>找到目标任务后，你可能想把多个任务并排对照——前往<a href="/docs/features/multi-pane.html">多任务分屏</a>了解分屏功能。</p>',26)])])}const b=r(s,[["render",n]]);export{u as __pageData,b as default};
